SELECT team_id, games_played
FROM team_stats
ORDER BY games_played DESC;

SELECT p.player_name
FROM players p
INNER JOIN player_stats ps ON p.player_id = ps.player_id
WHERE ps.games_played > (
  SELECT AVG(games_played) FROM player_stats
);

SELECT player_id, games_played
FROM player_stats
ORDER BY games_played DESC;

SELECT team_id, games_played
FROM team_stats
ORDER BY games_played DESC;

SELECT player_name
FROM players
ORDER BY player_name;
